/**
 * Pure validation functions for order operations.
 *
 * These functions contain no side effects and no database calls.
 * They validate inputs and state transitions for the order domain.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed. Throws if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(
      `Invalid status transition: ${from} -> ${to}`,
    );
  }
}

/**
 * Validate that an order has at least one item. Throws if empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Pure validation functions for user operations.
 *
 * These functions contain no side effects and no database calls.
 * They accept lookup results and validate business rules.
 */

import type { User } from '../models/user.js';

/**
 * Validate that an email is not already taken.
 * Accepts the result of an email lookup — if a user was found, the email is taken.
 */
export function validateEmailUnique(email: string, existingUser: User | undefined): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not taken by another user on update.
 * Accepts the result of an email lookup — if a user was found, the email is in use.
 */
export function validateEmailNotInUse(email: string, existingUser: User | undefined): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Validate that a user exists. Throws if not found.
 */
export function validateUserExists<T>(entity: T | undefined, id: string): asserts entity is T {
  if (!entity) {
    throw new Error(`User not found: ${id}`);
  }
}

/**
 * Pure validation functions for notification preferences.
 *
 * These functions contain no side effects and no database calls.
 * They evaluate preference rules given a preferences object.
 */

import type { EmailPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';

/**
 * Determine whether an email notification should be sent based on preferences.
 * Returns true if email is enabled, frequency is not 'never', and the
 * notification type is in the user's subscribed categories.
 */
export function shouldSendEmailNotification(
  prefs: EmailPreferences,
  notificationType: NotificationType,
): boolean {
  if (!prefs.enabled) {
    return false;
  }

  if (prefs.frequency === 'never') {
    return false;
  }

  if (!prefs.subscribedCategories.includes(notificationType)) {
    return false;
  }

  return true;
}

