import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateStatusTransition,
  validateOrderItems,
} from '../../src/validators/order.validator.js';

describe('order.validator', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });

  describe('validateOrderItems', () => {
    it('should not throw for non-empty items', () => {
      expect(() =>
        validateOrderItems([{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }]),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() => validateOrderItems([])).toThrow('Order must have at least one item');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailUnique,
  validateEmailNotInUse,
  validateUserExists,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  describe('validateEmailUnique', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailUnique('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when a user with that email exists', () => {
      expect(() => validateEmailUnique('alice@example.com', makeUser())).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailNotInUse('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when the email is in use', () => {
      expect(() => validateEmailNotInUse('alice@example.com', makeUser())).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });

  describe('validateUserExists', () => {
    it('should not throw when entity exists', () => {
      expect(() => validateUserExists(makeUser(), 'user-0001')).not.toThrow();
    });

    it('should throw when entity is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { shouldSendEmailNotification } from '../../src/validators/preferences.validator.js';
import type { EmailPreferences } from '../../src/models/user-preferences.js';

const makePrefs = (overrides: Partial<EmailPreferences> = {}): EmailPreferences => ({
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: ['order_confirmation', 'order_status_update', 'user_welcome', 'user_updated'],
  ...overrides,
});

describe('preferences.validator', () => {
  describe('shouldSendEmailNotification', () => {
    it('should return true when email is enabled and type is subscribed', () => {
      expect(shouldSendEmailNotification(makePrefs(), 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      expect(shouldSendEmailNotification(makePrefs({ enabled: false }), 'order_confirmation')).toBe(false);
    });

    it('should return false when frequency is never', () => {
      expect(shouldSendEmailNotification(makePrefs({ frequency: 'never' }), 'order_confirmation')).toBe(false);
    });

    it('should return false when notification type is not subscribed', () => {
      expect(
        shouldSendEmailNotification(makePrefs({ subscribedCategories: ['user_welcome'] }), 'order_confirmation'),
      ).toBe(false);
    });

    it('should return true for daily_digest frequency', () => {
      expect(shouldSendEmailNotification(makePrefs({ frequency: 'daily_digest' }), 'order_confirmation')).toBe(true);
    });

    it('should return true for weekly_digest frequency', () => {
      expect(shouldSendEmailNotification(makePrefs({ frequency: 'weekly_digest' }), 'order_confirmation')).toBe(true);
    });
  });
});

